import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";

function App() {
  const [socket, setSocket] = useState(null);
  const [username, setUsername] = useState("");
  const [room, setRoom] = useState("");
  const [message, setMessage] = useState("");
  const [messageList, setMessageList] = useState([]);
  const [showChat, setShowChat] = useState(false);
  const [users, setUsers] = useState([]);
  const [typingUser, setTypingUser] = useState("");

  const scrollRef = useRef();

  // connect socket
  useEffect(() => {
    const newSocket = io("http://localhost:5000");
    setSocket(newSocket);
    return () => newSocket.close();
  }, []);

  // auto scroll
  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messageList]);

  // join room
  const joinRoom = () => {
    if (username && room && socket) {
      setMessageList([]);
      socket.emit("join_room", { room, username });
      setShowChat(true);
    }
  };

  // send text
  const sendMessage = () => {
    if (message !== "" && socket) {
      const messageData = {
        room,
        author: username,
        message,
        time: new Date().toLocaleTimeString(),
        type: "text",
      };

      socket.emit("send_message", messageData);
      socket.emit("stop_typing", { room });
      setMessage("");
    }
  };

  // typing
  const handleTyping = () => {
    socket.emit("typing", { room, username });

    setTimeout(() => {
      socket.emit("stop_typing", { room });
    }, 1000);
  };

  // image upload
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append("file", file);
    formData.append("upload_preset", "chatapp"); // 🔥 your preset

    const res = await fetch(
      "https://api.cloudinary.com/v1_1/dlfepnsgd/image/upload",
      {
        method: "POST",
        body: formData,
      }
    );

    const data = await res.json();

    const messageData = {
      room,
      author: username,
      message: data.secure_url,
      time: new Date().toLocaleTimeString(),
      type: "image",
    };

    socket.emit("send_message", messageData);
  };

  // listeners
  useEffect(() => {
    if (!socket) return;

    socket.on("load_messages", (data) => setMessageList(data));

    socket.on("receive_message", (data) =>
      setMessageList((list) => [...list, data])
    );

    socket.on("online_users", (data) => setUsers(data));

    socket.on("typing", (user) => setTypingUser(user));
    socket.on("stop_typing", () => setTypingUser(""));

    return () => {
      socket.off("receive_message");
      socket.off("online_users");
      socket.off("typing");
      socket.off("stop_typing");
    };
  }, [socket]);

  return (
    <div className="h-screen flex bg-gray-900 text-white">

      {/* Sidebar */}
      <div className="w-1/4 bg-gray-800 p-4">
        <h2 className="text-lg font-bold mb-3">Chats</h2>
        <div className="p-2 bg-gray-700 rounded mb-2">
          Room: {room}
        </div>

        <h2 className="mt-4 text-lg font-bold">Online Users</h2>
        {users.map((user, i) => (
          <div key={i} className="p-2 bg-gray-700 rounded mt-2">
            {user}
          </div>
        ))}
      </div>

      {/* Chat */}
      <div className="flex-1 flex items-center justify-center">

        {!showChat ? (
          <div className="bg-white text-black p-6 rounded shadow-lg w-80">
            <h2 className="text-xl font-bold mb-3 text-center">Join Chat</h2>

            <input
              placeholder="Username"
              onChange={(e) => setUsername(e.target.value)}
              className="block mb-2 p-2 border w-full"
            />

            <input
              placeholder="Room"
              onChange={(e) => setRoom(e.target.value)}
              className="block mb-3 p-2 border w-full"
            />

            <button
              onClick={joinRoom}
              className="bg-blue-500 text-white p-2 w-full rounded"
            >
              Join
            </button>
          </div>
        ) : (
          <div className="w-[500px] bg-white text-black rounded flex flex-col h-[600px] shadow-lg">

            {/* Header */}
            <div className="bg-blue-500 text-white p-3 text-center font-bold">
              Room: {room}
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-3 bg-gray-100">
              {messageList.map((msg, index) => (
                <div
                  key={index}
                  className={`flex ${
                    msg.author === username ? "justify-end" : "justify-start"
                  }`}
                >
                  <div
                    className={`p-2 rounded m-1 max-w-[70%] ${
                      msg.author === username
                        ? "bg-green-500 text-white"
                        : "bg-gray-300"
                    }`}
                  >
                    <b>{msg.author}</b>

                    {msg.type === "image" ? (
                      <img
                        src={msg.message}
                        alt="img"
                        className="w-40 mt-1 rounded"
                      />
                    ) : (
                      <div>{msg.message}</div>
                    )}

                    <div className="text-xs">{msg.time}</div>
                  </div>
                </div>
              ))}

              <div ref={scrollRef}></div>
            </div>

            {/* Typing */}
            {typingUser && (
              <div className="text-sm px-3 text-gray-500">
                {typingUser} is typing...
              </div>
            )}

            {/* Input */}
            <div className="flex p-2 border-t gap-2">
              <input
                value={message}
                onChange={(e) => {
                  setMessage(e.target.value);
                  handleTyping();
                }}
                className="flex-1 border p-2 rounded"
                placeholder="Type message..."
              />

              <input type="file" onChange={handleFileUpload} />

              <button
                onClick={sendMessage}
                className="bg-blue-500 text-white px-4 rounded"
              >
                Send
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
